import{_ as e}from"./chunks/lekt4301.Br9NsjuL.js";import{_ as r,o as a,c as i,ag as d}from"./chunks/framework.DXGyWiRo.js";const l="/images/lekt4302.jpg",n="/images/lekt4303.jpg",s="/images/lekt4304.jpg",o="/images/lekt4305.jpg",p="/images/lekt4306.jpg",h="/images/lekt4307.jpg",u="/images/lekt4308.jpg",b="/images/lekt4309.jpg",w=JSON.parse('{"title":"Lektion 43","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion43.md","filePath":"lektionen/lektion43.md"}'),m={name:"lektionen/lektion43.md"};function c(k,t,g,f,q,P){return a(),i("div",null,[...t[0]||(t[0]=[d('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-43" tabindex="-1">Lektion 43 <a class="header-anchor" href="#lektion-43" aria-label="Permalink to &quot;Lektion 43&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>43.1. Personalendungen der 2. Person (मध्यमः = &quot;mittlere &lt;Person&gt;&quot;)</li><li>43.2. Bildung der Verbalformen der 2. Person (मध्यमः) <ul><li>43.2.1. Thematische Stämme <ul><li>43.2.1.1. Erste Präsensklasse (भ्वादि)</li><li>43.2.1.2. Sechste Präsensklasse (तुदादि)</li><li>43.2.1.3. Vierte Präsensklasse (दिवादि)</li><li>43.2.1.4. Zehnte Präsensklasse (चुरादि) und Kausative</li><li>43.2.1.5. Passiv</li><li>43.2.1.6. Futur (ऌट्) <ul><li>43.2.1.6.1. अनिट्-Bildungen</li><li>43.2.1.6.2. सेट्-Bildungen</li></ul></li></ul></li></ul></li><li>43.3. Das Personalpronomen der zweiten Person</li><li>43.4. Wortliste</li><li>43.5. Übung</li><li>43.6. संवादः = Gespräch</li></ul><h2 id="_43-1-personalendungen-der-2-person-मध्यमः-mittlere-lt-person-gt" tabindex="-1">43.1. Personalendungen der 2. Person (मध्यमः = &quot;mittlere &lt;Person&gt;&quot;) <a class="header-anchor" href="#_43-1-personalendungen-der-2-person-मध्यमः-mittlere-lt-person-gt" aria-label="Permalink to &quot;43.1. Personalendungen der 2. Person (मध्यमः = &quot;mittlere &amp;lt;Person&amp;gt;&quot;)&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Primärendungen</td><td>-si</td><td>-tha</td></tr><tr><td>Sekundärendungen</td><td>-s</td><td>-ta</td></tr><tr><td>Perfektendungen</td><td>-tha</td><td>-a</td></tr></tbody></table><p>Beachten Sie, dass die Sekundärendung der 2.pl.P. identisch ist mit der Sekundärendung der 3.sg.Ā.</p><h2 id="_43-2-bildung-der-verbalformen-der-2-person-मध्यमः" tabindex="-1">43.2. Bildung der Verbalformen der 2. Person (मध्यमः) <a class="header-anchor" href="#_43-2-bildung-der-verbalformen-der-2-person-मध्यमः" aria-label="Permalink to &quot;43.2. Bildung der Verbalformen der 2. Person (मध्यमः)&quot;">​</a></h2><p>2.Person:</p><ul><li>Singular: &quot;du&quot;</li><li>Plural: &quot;ihr&quot; (mehr als zwei!)</li></ul><h3 id="_43-2-1-thematische-stamme" tabindex="-1">43.2.1. Thematische Stämme <a class="header-anchor" href="#_43-2-1-thematische-stamme" aria-label="Permalink to &quot;43.2.1. Thematische Stämme&quot;">​</a></h3><p><img src="'+e+'" alt=""></p><p>Die 3.sg.Ā.Imperfekt bzw. Optativ ist formgleich mit der 2.pl.P.Imperfekt bzw. Optativ!</p><h4 id="_43-2-1-1-erste-prasensklasse-भ्वादि" tabindex="-1">43.2.1.1. Erste Präsensklasse (भ्वादि) <a class="header-anchor" href="#_43-2-1-1-erste-prasensklasse-भ्वादि" aria-label="Permalink to &quot;43.2.1.1. Erste Präsensklasse (भ्वादि)&quot;">​</a></h4><p>भू 1P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>भवसि</td><td></td></tr><tr><td>bho + a + si</td><td>भवथ</td><td>&lt;भवसे&gt;</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अभवस्</td><td>अभवत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>भवेस्</td><td>भवेत</td></tr></tbody></table></blockquote><h4 id="_43-2-1-2-sechste-prasensklasse-तुदादि" tabindex="-1">43.2.1.2. Sechste Präsensklasse (तुदादि) <a class="header-anchor" href="#_43-2-1-2-sechste-prasensklasse-तुदादि" aria-label="Permalink to &quot;43.2.1.2. Sechste Präsensklasse (तुदादि)&quot;">​</a></h4><p>विश् 6P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>विशसि</td><td>विशथ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अविशस्</td><td>अविशत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>विशेस्</td><td>विशेत</td></tr></tbody></table></blockquote><h4 id="_43-2-1-3-vierte-prasensklasse-दिवादि" tabindex="-1">43.2.1.3. Vierte Präsensklasse (दिवादि) <a class="header-anchor" href="#_43-2-1-3-vierte-prasensklasse-दिवादि" aria-label="Permalink to &quot;43.2.1.3. Vierte Präsensklasse (दिवादि)&quot;">​</a></h4><p>नृत् 4P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>नृत्यसि</td><td>नृत्यथ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अनृत्यस्</td><td>अनृत्यत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>नृत्येस्</td><td>नृत्येत</td></tr></tbody></table></blockquote><h4 id="_43-2-1-4-zehnte-prasensklasse-चुरादि-und-kausative" tabindex="-1">43.2.1.4. Zehnte Präsensklasse (चुरादि) und Kausative <a class="header-anchor" href="#_43-2-1-4-zehnte-prasensklasse-चुरादि-und-kausative" aria-label="Permalink to &quot;43.2.1.4. Zehnte Präsensklasse (चुरादि) und Kausative&quot;">​</a></h4><p>चुर् 10U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>चोरयसि</td><td>चोरयथ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अचोरयस्</td><td>अचोरयत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>चोरयेस्</td><td>चोरयेत</td></tr></tbody></table></blockquote><h4 id="_43-2-1-5-passiv" tabindex="-1">43.2.1.5. Passiv <a class="header-anchor" href="#_43-2-1-5-passiv" aria-label="Permalink to &quot;43.2.1.5. Passiv&quot;">​</a></h4><p>ईक्ष् 1Ā</p><blockquote><table tabindex="0"><thead><tr><th></th><th>एकवचनम्</th><th>बहुवचनम्</th></tr></thead><tbody><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>ईक्ष्यसे</td><td></td></tr><tr><td>īkṣ-ya-se</td><td>ईक्ष्यध्वे</td><td></td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>ऐक्ष्यथास्</td><td>ऐक्ष्यध्वम्</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>ईक्ष्येथास्</td><td>ईक्ष्येध्वम्</td></tr></tbody></table></blockquote><h4 id="_43-2-1-6-futur-ऌट्" tabindex="-1">43.2.1.6. Futur (ऌट्) <a class="header-anchor" href="#_43-2-1-6-futur-ऌट्" aria-label="Permalink to &quot;43.2.1.6. Futur (ऌट्)&quot;">​</a></h4><h4 id="_43-2-1-6-1-अनिट्-bildungen" tabindex="-1">43.2.1.6.1. अनिट्-Bildungen <a class="header-anchor" href="#_43-2-1-6-1-अनिट्-bildungen" aria-label="Permalink to &quot;43.2.1.6.1. अनिट्-Bildungen&quot;">​</a></h4><p>दा 3U</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>दास्यसि</td><td>दास्यथ</td></tr></tbody></table></blockquote><h4 id="_43-2-1-6-2-सेट्-bildungen" tabindex="-1">43.2.1.6.2. सेट्-Bildungen <a class="header-anchor" href="#_43-2-1-6-2-सेट्-bildungen" aria-label="Permalink to &quot;43.2.1.6.2. सेट्-Bildungen&quot;">​</a></h4><p>भू 1P</p><blockquote><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>भविष्यसि</td><td>भविष्यथ</td></tr></tbody></table></blockquote><h2 id="_43-3-das-personalpronomen-der-zweiten-person" tabindex="-1">43.3. Das Personalpronomen der zweiten Person <a class="header-anchor" href="#_43-3-das-personalpronomen-der-zweiten-person" aria-label="Permalink to &quot;43.3. Das Personalpronomen der zweiten Person&quot;">​</a></h2><ul><li>Singular: त्वद् &quot;du&quot;</li><li>Plural: युष्मद् &quot;ihr&quot;</li></ul><blockquote><p>|   | एकवचनम्<br> त्वद् | बहुवचनम्<br> युष्मद् | | --- | --- | --- | | प्रथमा | त्वम् | यूयम् | | द्वितीया | त्वाम्<br> त्वा | युष्मान्<br> वस् | | तृतीया | त्वया | युष्माभिस् | | चतुर्थी | तुभ्यम्<br> ते | युष्मभ्यम्<br> वस् | | पञ्चमी | त्वत् | युष्मत् | | षष्ठी | तव<br> ते | युष्माकम्<br> वस् | | सप्तमी | त्वयि | युष्मासु |</p></blockquote><p>Die Formen त्वा, ते, वस् dürfen nicht an erster Stelle eines Satzes oder einer Vershälfte gebraucht werden. Auch vor च, वा, एव und einigen anderen Partikeln dürfen sie nicht verwendet werden:</p><blockquote><p>त्वां मां च &quot;dich und mich&quot;</p></blockquote><h2 id="_43-4-wortliste" tabindex="-1">43.4. Wortliste <a class="header-anchor" href="#_43-4-wortliste" aria-label="Permalink to &quot;43.4. Wortliste&quot;">​</a></h2><p>ज्ञा + आ Kausativ आज्ञापयति : befehlen, anordnen</p><p>आपण m.: Markt</p><p><img src="'+l+'" alt=""><br> Abb.: आपणः<br> Orissa = ଓଡ଼ିଶା<br> [Bildquelle: Rita Willaert. -- <a href="http://www.flickr.com/photos/rietje/324020365/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/rietje/324020365/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>सत्वर 3: schnell, eilig</p><p>पण्य 3: käuflich; n.: Ware, Handel</p><p><img src="'+n+'" alt=""><br> Abb.: पण्यानि<br> Jamshedpur = जमशेदपुर<br> [Bildquelle: amrita b. -- <a href="http://www.flickr.com/photos/amrita_b/63071274/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/amrita_b/63071274/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>आम् : ja</p><p>सम m. = वर्ष n.</p><p>-आयुत 3: versehen mit</p><p>भद्र 3: gut, glücklich; Vokativ: mein Lieber!</p><p>समय m. (zu सम्-इ): Übereinkunft, Vertrag, Frist, Termin, Zeit</p><p>निश्चित 3: entschieden, festgesetzt</p><p>नोचेत् : wenn nicht, sonst</p><p>विलम्ब n.m.: Verzögerung, Verspätung</p><p>विपणि f.: Laden</p><p><img src="'+s+'" alt=""><br> Abb.: विपणिः<br> Haridwar = हरिद्वार<br> [Bildquelle: mckaysavage. -- <a href="http://www.flickr.com/photos/mckaysavage/2085721947/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mckaysavage/2085721947/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>वणिज् m.: Kaufmann</p><p><img src="'+o+'" alt=""><br> Abb.: वणिक्<br> Kanchipuram = காஞ்சிபுரம<br> [Bildquelle: visio. -- <a href="http://www.flickr.com/photos/visio/421217297/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/visio/421217297/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>वर 3: bester</p><p>शीघ्र 3: schnell, rasch</p><p>वत्स m.: Kalb, Junges, Kind ; Vok.: mein Lieber</p><p><img src="'+p+'" alt=""><br> Abb.: वत्सः<br> Wasserbüffel (<em>Bubalus bubalis</em>), Mangalore = ಮಂಗಳೂರು<br> [Bildquelle: wildxplorer. -- <a href="http://www.flickr.com/photos/krayker/2123046126/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/krayker/2123046126/</a>. -- Zugriff am 2009-001-06. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><p>उत्तम 3: oberster, bester</p><p>अल्प 3: klein, gering</p><p>मूल्य n.: Wert, Preis</p><p>कियत् 3: wie groß</p><p>शर्करा f.: Zucker (das deutsche &quot;Zucker&quot; geht über italienisch zucchero, von dort über arabisch sukkar - سكر und persisch äkär - شکر auf das Sanskrit शर्करा zurück!)</p><p>अधिक 3: zusätzlich, überschüssig, ausserordendlich</p><p>तर्हि : damals, dann ; darum, also</p><p>तुल् 10 तुलयति । तोलयति : wägen</p><p><img src="'+h+'" alt=""><br> Abb.: तोलन्ति<br> [Bildquelle: Ray Witlin / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2183198505/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2183198505/</a>. -- Zugriff am 2009-01-06. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>कर्गल n.: Papier</p><p>संपुट m.: Dose (hier: Paket, Bündel)</p><p>पुरतस् : vorn, davor, vor</p><p>श्रेष्ठिन् m.: reicher Kaufmann</p><p>जव 3: schnell, eilig</p><p>द्रु 1P द्रवति rennen</p><blockquote><p>Perf. IIIa दुद्राव, दुद्रुवुर्<br> Fut. द्रोष्यति<br> Pass. द्रूयते<br> Kaus. द्रावयति<br> PPP द्रुत<br> Absol. -द्रुत्य<br> Inf. द्रोतुम्</p></blockquote><p>रे Interjektion: He! Du da!</p><p>अन्यद् 3: ein anderer (Deklination wie यद् )</p><p>वञ्चक m.: Betrüger</p><p>पश्चात्ताप m.: Reue</p><p>इत्थम् Adv.: auf diese Weise, so</p><p>दिन n.: Tag</p><p>जन्मन् n.: Geburt</p><p>आनन्द m.: Wonne, Freude</p><h2 id="_43-5-ubung" tabindex="-1">43.5. Übung <a class="header-anchor" href="#_43-5-ubung" aria-label="Permalink to &quot;43.5. Übung&quot;">​</a></h2><p>A) Bilden Sie die in Zeit, Zahl, Modus u. s. w. entsprechende 2. Person zu folgenden Verbformen:</p><ol><li>आर्हम्</li><li>कुप्येम</li><li>ऐच्छन्</li><li>ईक्षेरन्</li><li>कल्पने</li><li>क्रामन्ति</li><li>क्रेष्याम</li><li>गच्छेयम्</li><li>गायति</li><li>चर्यते</li><li>चेष्यन्ति</li><li>जायेय</li><li>आज्ञापयत्</li><li>विजयते</li><li>जीव्येत</li><li>तुदामः</li><li>अतरन्</li><li>त्यजामि</li><li>दहेयम्</li><li>आदास्ये</li><li>दिशति</li><li>अदूष्यम्</li><li>दृश्यामहे</li><li>नश्येयुः</li><li>आनीयामहि</li><li>नृत्यामि</li><li>पचेत्</li><li>पतिष्यामि</li><li>आपद्यत</li><li>पिबामः</li><li>अपृच्छ्ये</li><li>बुध्यामहे</li><li>भजेम</li><li>प्राभवन्</li><li>भरिष्यन्ते</li><li>मन्ये</li><li>मुच्येरन्</li><li>अम्रियन्त</li><li>यजेत</li><li>युध्येमहि</li><li>अरक्षन्</li><li>लप्स्यन्ते</li><li>अवदम्</li><li>औह्ये</li><li>वसन्ति</li><li>अवावर्तत</li><li>विशामि</li><li>शोचामः</li><li>वर्धेत</li><li>सीदामि</li><li>तिष्ठन्ति</li><li>आहरत्</li></ol><p>B) Übersetzen Sie ins Sanskrit:</p><p>1. Warum sitzt ihr während der Lehrer steht?</p><p>2. Bezweifelst du, ob eine gute Tat eine gute Frucht  hat?</p><p>3. Werdet ihr dem Vater den innersten Tempelschrein zeigen?</p><p>4. Das Preislied welches Dichters hast du gesungen?</p><p>5. Werdet ihr diese Früchte verkaufen?</p><p>6. Was hast du befohlen?</p><p>7. Wann hast du dich in Benares aufgehalten (वृत्)?</p><p>8. Habt ihr als Opferherren die Götter mit einem Opfer verehrt?</p><p>9. In welcher Stadt wurdest du geboren?</p><p>10. Wie rettest du dich (überschreitest) vor dem Feind?</p><p><img src="'+u+'" alt=""><br> Abb.: कदा पूराववर्तथाः ।<br> रथयात्रा २००७, पूरि<br> [Bildquelle: G.-U. Tolkiehn / Wikipedia. GNU FDLicense]</p><h2 id="_43-6-संवादः-gesprach" tabindex="-1">43.6. संवादः = Gespräch <a class="header-anchor" href="#_43-6-संवादः-gesprach" aria-label="Permalink to &quot;43.6. संवादः = Gespräch&quot;">​</a></h2><table tabindex="0"><thead><tr><th>संवादः</th><th>Erklärungen</th></tr></thead><tbody><tr><td>सुरेशः : अशोक१ क्व गच्छसीदानीम् ॥</td><td>1 Vokativ sg.</td></tr><tr><td>अशोकः : आपणे गच्छामि । सत्वरमेव कानिचित्पण्यानि क्रीत्वा निवर्तिष्ये ॥</td><td></td></tr><tr><td>सुरेशः : किं कश्चिदुत्सवो ऽद्य तव गृहे ॥</td><td></td></tr><tr><td>अशोकः : आम् । अद्य पितृपादानां२ जन्मदिनोत्सवः ॥</td><td>2 -पाद pl. kann an Namen, Titel usw. angefügt werden, um Respekt auszudrücken</td></tr><tr><td>सुरेशः : किं वयस्तव३ पितृचरणानाम् ॥</td><td>3 Nom.Akk.sg zu वयस् n. &quot;Alter&quot;</td></tr><tr><td>अशोकः : पञ्चषष्टिसमायुतं४ मम पितुर्वयः । अद्य मम गृहे बहवः संबन्धिनो मित्राणि चागमिष्यन्ति । त्वयाप्यागब्तव्यम् ॥</td><td>4 पञ्चषष्ति  fünfundsechzig</td></tr><tr><td>सुरेशः : भद्र५ कतिवादन५क् आगमिष्यन्ति जनाः ॥</td><td>5 Vokativ sg.</td></tr><tr><td>5k वादन n. &quot;-Uhr&quot;</td><td></td></tr></tbody></table><p>| | अशोकः : समयं किं पृच्छसि । षड्वादनं६ यावदागच्छ७॥ | 6 षड् &quot;sechs&quot;</p><p>7 2.sg.Imperativ</p><p>| | सुरेशः : सार्धषड्वादनं यावदागच्छामि चेत् ॥ |   | | अशोकः : नैव षड्वादन एव निश्चितरूपेणागन्तव्यं त्वया ॥ |   | | सुरेशः : अस्तु८ । तर्हि गच्छ त्वं । नोचेद्विलम्बो भविष्यति ॥ | 8 3.sg.Imperativ zu अस् 2P | | अशोकः :  (विपण्यां प्रविशति वणिजमुपसृत्य वदति च) अयि वणिग्वर९ कानिचित्पण्यानि क्रेतुमागतो ऽहम् । देहि१० शीघ्रं मय्हम् ॥ | 9 Vokativ sg.</p><p>10 2.sg.Imperativ P zu दा 3U</p><p>| | वणिक्११ : वत्स त्वं किंकिं क्रेतुमिच्छसि । मम विपणौ बहून्युत्तमोत्तमानि पण्यानि सन्ति तानि च स्वल्पमूल्यानि । वद१२ कियत्परिमाणं किं क्रेतुमिच्छसि ॥ | 11 Nom.sg. zu वणिज् m.</p><p>12 2.sg.Imperativ</p><p>| | अशोकः :  सेरभारा१३ शर्करा कियता मूल्येन विक्रीयते ॥ | 13 सेर = Seer (= 0.93310 kg) | | वणिक् :  नाधिक्यं मूल्यम् । केवलमष्टाणकेन१४ दास्यामि सेरभारां शर्कराम् ॥ | 14 आणक = Anna = 1/16 Rupee | | अशोकः :  तर्हि तोलयित्वा शीघ्रं सेरपरिमितां शर्करां देहि१५ ॥ | 15 2.sg.Imperativ P zu दा 3U | | वणिक् :  (शर्करां कर्गले संपुटीकृत्य) बाल१६ गृहाण१७ शर्कराम् । देहि च मह्यमाणकाष्टकम्१८ । सत्वरं देहि ॥ | 16 Vokativ sg.</p><p>17 2.sg.Imperativ</p><p>18 अष्ट &quot;acht&quot;</p><p>| | अशोकः : (आदाय हस्ते तस्य भारं चाल्पं विलोक्य) भो वनिक् । नैषा सेरभारा शर्करा दृश्यते । पुनः सम्यक्तोलयित्वा१९ देहि ॥ | 19 सम्यक् Adv. &quot;richtig&quot; | | वणिक् : (सहासम्) किमनेन । अकिञ्चिद्करमेतत् । तव भारवहनक्लेशो ऽल्पो भविष्यति ॥ |   | | अशोकः :  (मनसि२० किंचिद्विचार्याणकचतुष्टयं२१ च तस्य पुरत उपस्थाप्य) भो श्रेष्ठिन्गृहाण२२ मूल्यम् । मया हि शीघ्रं गृहं गन्तव्यम् ॥ (इत्युक्त्वा ततः प्रस्थितः) | 20 Lok.sg. zu मनस् n. &quot;Geist&quot;</p><p>21 चतुष्टय &quot;Anzahl von vier&quot;</p><p>22 Imperativ.sg.</p><p>| | वणिक् :  रे बालक२३ । एह्येहि२४ शृणु२५ तावत् ।  अल्पमेव मूल्यं दत्त्वा क्व व्रजसि । आणकचतुष्टयमन्यदपि देहि ॥ | 23 Vokativ sg.</p><p>24 2.g.Imperativ P zu इ+आ</p><p>25 2.sg.Imperativ P</p><p>| | अशोकः : श्रेष्ठिन्२६ । किमनेन । अकिंचित्करमेतत् । नाणकगणनाक्लेशस्ते ऽल्पीयान्भविष्यति२७ ॥ (इत्युक्त्वा ततो जवेन द्रवति)</p><p>(विपणिस्थो वञ्चको वनिग्न२८ किमपि कर्तुमशक्नोत्केवलं तस्य मनसि२९ पश्चात्ताप एवासीत्)</p><p>अशोको गृहमागत्य सर्वमपीतिवृत्तमकथयत् । तत्रस्था सर्वे ऽपि बान्धवा मित्राणि च परमानन्दं प्रापुः । इत्थं जन्मोत्सवः सानन्दं समाप्तिं यातः ॥</p><p>| 26 Vokativ sg.</p><p>27 Nom.sg.m. Komparativ zu अल्प = &quot;ganz gering&quot;</p><p>28 वणिक्  Nom.sg. zu वणिज्</p><p>29 Lok.sg. zu मनस् n. &quot;Geist&quot;</p><p>| | (Nach: Saral Sanskrit Shikshak III, S. 4f.) |   |</p><p><img src="'+b+'" alt=""><br> Abb.: शर्करा<br> गुड़ (शक्कर),<br> [Bildquelle: Carol Mitchell. -- <a href="http://www.flickr.com/photos/webethere/2178184852/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/webethere/2178184852/</a>. -- Zugriff am 2009-01-07. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine Bearbeitung)]</p>',128)])])}const z=r(m,[["render",c]]);export{w as __pageData,z as default};
